export const GUIDES: Guide[] = [
  { id: "asylum-waiting", cat: "Asylum Process", icon: "⏳", content: { en: { title: "Waiting for Your Asylum Decision", summary: "What to expect while your asylum claim is being processed — your cards, rights, payments, and what happens next.", steps: ["Your ARC card (Application Registration Card) is your primary ID while your asylum claim is active. It proves you have an ongoing claim. Use it to: register with a GP or NHS service, access asylum support accommodation, open certain bank accounts (Monese accepts an ARC card), and enrol in ESOL or college.", "Your ARC card CANNOT be used as a right-to-work document unless it specifically says 'Permitted to Work' on the front. It is NOT a travel document — you cannot leave the UK and re-enter on it. It is NOT equivalent to a BRP or eVisa.", "Your ASPEN card is your asylum support payment card. As of 2025/26 the standard rate is £49.18/week for a single adult (higher if you have children). Payments arrive weekly. The card works like a Visa debit card at any shop that accepts Visa. Note: older ASPEN cards cannot withdraw cash from ATMs.", "Current Home Office processing times: 6–18+ months for most claims, and longer for complex cases or certain nationalities. You can check your case status by contacting the Asylum Helpline on 0808 8000 631 (free, Mon–Fri 9am–5pm) or by asking your solicitor to make enquiries.", "If you need to chase the Home Office: ask your solicitor to write to the case-owner or the National Asylum Intake Unit. If you do not have a solicitor, call the Asylum Helpline (0808 8000 631) or contact a local law centre.", "If your decision is POSITIVE (refugee status granted): you will receive a refugee recognition letter. You then have 56 days to leave asylum accommodation and set yourself up — see the 56-Day Move-On guide for everything you must do immediately.", "If your decision is NEGATIVE: you will usually have the right to appeal. You have 14 or 28 days to lodge an appeal (the letter will say which). Always consult a solicitor immediately — do not miss the deadline. If you have new evidence not previously considered, you may be able to submit a 'fresh claim'.", "Your rights while waiting: you have the right to free NHS care, your children have the right to attend school, you have the right to asylum accommodation and Section 95 support if destitute. If you are refused but cannot safely return to your home country, you may qualify for Section 4 support. You also have the right to free legal aid for your asylum case.", "Reporting requirements: you may be required to report regularly to an immigration reporting centre. The letter you received will tell you your reporting schedule. Missing a reporting appointment without a good reason can lead to the Home Office treating you as having absconded, which can seriously harm your case.", "⚠ Never pay anyone to check your case status — it is free. Never give your ARC card or ASPEN card to anyone else."] } }, cost: "Free", time: "Ongoing — 6–18+ months", bring: ["ARC card", "Any letters from the Home Office"], links: [{ name: "Asylum Helpline (0808 8000 631)", url: "https://www.gov.uk/asylum-support" }, { name: "Check your asylum case (GOV.UK)", url: "https://www.gov.uk/asylum-support/further-information" }, { name: "Legal aid for asylum (GOV.UK)", url: "https://www.gov.uk/legal-aid" }, { name: "Refugee Council asylum support", url: "https://www.refugeecouncil.org.uk/help-for-refugees/asylum-support/" }, { name: "Section 4 support (GOV.UK)", url: "https://www.gov.uk/asylum-support/section-4-support" }] },
  { id: "evisa", cat: "Digital Status", icon: "📱", content: { en: { title: "Your eVisa & UKVI Account", summary: "BRPs expired Dec 2024. Your immigration status is now 100% digital.", steps: ["All BRPs expired 31 December 2024. Your status hasn't changed — only how you prove it.", "You can still use an expired BRP to access the online share code service for up to 18 months after its expiry date (until June 2026 for most people).", "Since June 2025, expired BRPs are NOT accepted for travel by airlines.", "Check your email for noreply@notifications.service.gov.uk — your UKVI account may already exist.", "No account? Visit gov.uk/evisa — free, takes 10 minutes.", "Link your passport to your UKVI account BEFORE travelling.", "From 25 Feb 2026, all new visa applicants receive eVisas only — no more vignette stickers.", "Screenshot your eVisa status page and save offline — essential without internet.", "⚠ ~300,000 UK residents still haven't set up their eVisa. Do it now."] } }, cost: "Free", time: "10 min", bring: ["Email address", "Passport or BRP number"], links: [{ name: "Set up eVisa (GOV.UK)", url: "https://www.gov.uk/evisa" }, { name: "Update UKVI details", url: "https://www.gov.uk/evisa/update-your-ukvi-account-details" }, { name: "eVisa help videos", url: "https://www.gov.uk/government/publications/updates-on-the-move-to-evisas/updates-on-the-move-to-evisas" }] },
  { id: "sharecode", cat: "Digital Status", icon: "🔗", content: { en: { title: "Share Codes", summary: "Prove your right to work, rent, or access services.", steps: ["Log in to UKVI → 'Prove your status'. Choose: Right to Work, Right to Rent, or General.", "Right to Work codes start with 'W'. Right to Rent codes start with 'R'. Don't mix them up.", "Codes valid 90 days. Generate a new one each time you need it.", "Give the code + your date of birth to your employer or landlord. They verify online.", "EU Settled Status: share code is your ONLY proof. No physical card exists.", "⚠ Never pay anyone for a share code. The GOV.UK service is always free."] } }, cost: "Free", time: "2 min", bring: ["UKVI account login"], links: [{ name: "Prove right to work (GOV.UK)", url: "https://www.gov.uk/prove-right-to-work" }, { name: "Prove right to rent (GOV.UK)", url: "https://www.gov.uk/prove-right-to-rent" }, { name: "Check someone's status (GOV.UK)", url: "https://www.gov.uk/view-right-to-work" }] },
  { id: "nrpf", cat: "Digital Status", icon: "⚠️", content: { en: { title: "No Recourse to Public Funds (NRPF)", summary: "NRPF restricts most benefits. Know what you CAN still access.", steps: ["NRPF means you cannot claim: Universal Credit, Housing Benefit, Child Tax Credit.", "You CAN still access: full NHS care, state schools, Statutory Sick Pay, child protection.", "Destitute with children? Your council MUST help under Section 17, Children Act 1989.", "Changed circumstances (illness, domestic abuse)? Apply to have NRPF removed.", "NRPF Network provides free specialist advice."] } }, cost: "Free", time: "Read now", bring: [], links: [{ name: "NRPF Network", url: "https://www.nrpfnetwork.org.uk" }, { name: "Find immigration adviser (GOV.UK)", url: "https://www.gov.uk/find-an-immigration-adviser" }] },
  { id: "bank", cat: "Money", icon: "🏦", content: { en: { title: "Opening a Bank Account", summary: "Asylum seekers: Monese accepts your ARC card directly — no share code needed. Others can use Revolut, Monzo, or Starling with a share code.", steps: ["Asylum seekers without a share code: Monese accepts your ARC card directly. No fixed address required. Apply in the Monese app.", "Revolut, Monzo, and Starling all accept share code + selfie/face scan. Approved in hours — often same day. Note: these banks generally require a share code or passport — asylum seekers who surrendered their passport to the Home Office may not have these.", "If digital banks decline: go to Barclays, NatWest, Lloyds, or HSBC in person and ask specifically for a 'basic bank account'.", "You do NOT need a fixed address. A hostel address, friend's address, or charity office address is fine.", "Credit unions accept members without UK credit history — useful for borrowing small amounts later.", "⚠ Never pay anyone to open a bank account. It is always free. Any fee request is a scam."] } }, cost: "Free", time: "Same day", bring: ["ARC card (asylum seekers)", "Share code or passport", "Smartphone"], links: [{ name: "Monese", url: "https://monese.com" }, { name: "Revolut", url: "https://www.revolut.com" }, { name: "Monzo", url: "https://monzo.com" }, { name: "Starling", url: "https://www.starlingbank.com" }, { name: "Basic bank account (GOV.UK)", url: "https://www.gov.uk/government/collections/basic-bank-accounts" }] },
  { id: "uc", cat: "Money", icon: "💷", content: { en: { title: "Universal Credit", summary: "Main working-age benefit. Request an Advance on day one.", steps: ["Apply online or call 0800 328 5644 (free).", "Request UC Advance on day one — interest-free loan for the 5-week wait.", "Report full housing costs so Housing Element is included.", "Claim Child Benefit separately — after 7 Apr 2025, backdated to refugee grant date (max 3 months).", "Update your UC journal every assessment period — missed updates pause payments.", "NRPF on your eVisa? You cannot claim UC. See the NRPF guide."] } }, cost: "Free", time: "5 weeks — Advance covers wait", bring: ["Share code", "Bank details", "Rent info"], links: [{ name: "Apply for UC (GOV.UK)", url: "https://www.gov.uk/universal-credit/how-to-claim" }, { name: "Child Benefit (GOV.UK)", url: "https://www.gov.uk/child-benefit" }] },
  { id: "ni", cat: "Money", icon: "🔢", content: { en: { title: "National Insurance Number", summary: "Needed for work and tax. Start working before it arrives.", steps: ["Apply online — free, takes 20 minutes.", "You CAN work and claim benefits while waiting — tell employer it's pending.", "Format: AB 12 34 56 C. Yours for life.", "Never share your NI number on social media."] } }, cost: "Free", time: "4–16 weeks", bring: ["Passport"], links: [{ name: "Apply for NI number (GOV.UK)", url: "https://www.gov.uk/apply-national-insurance-number" }] },
  { id: "tax", cat: "Money", icon: "📋", content: { en: { title: "Tax & Payslips", summary: "How UK tax works. What to save for visa applications.", steps: ["Tax is deducted automatically via PAYE. Check your payslip monthly.", "Personal Allowance: £12,570/year tax-free. Basic rate 20% up to £50,270.", "Save every P60 and P45 — critical for future visa applications.", "Self-employed? Register with HMRC within 3 months of starting.", "⚠ Not all visas allow self-employment — check your eVisa conditions first."] } }, cost: "Free", time: "Ongoing", bring: ["NI number"], links: [{ name: "Income tax guide (GOV.UK)", url: "https://www.gov.uk/income-tax" }, { name: "Register as self-employed (GOV.UK)", url: "https://www.gov.uk/set-up-self-employed" }] },
  { id: "gp", cat: "Healthcare", icon: "🏥", content: { en: { title: "NHS & GP Registration", summary: "Free NHS care for everyone — regardless of immigration status or address.", steps: ["Find your nearest GP on the NHS website.", "GPs legally CANNOT refuse you — no address, no ID, any immigration status.", "Asylum seekers receive full free NHS care including hospital treatment, mental health, maternity, and prescriptions. You do NOT need to pay the Immigration Health Surcharge.", "Show your ARC card at the GP surgery — it confirms your right to register.", "HC2 certificate: asylum seekers on asylum support automatically qualify for free prescriptions, dental, and optical care — apply via form HC1.", "Download the NHS App (free) — book appointments, repeat prescriptions, NHS number, health records.", "NHS 111 for urgent medical advice (free, 24/7). 999 for emergencies.", "Free dental if you're on UC — tell the dentist before any treatment."] } }, cost: "Free", time: "Same day", bring: ["Passport (helpful, not required)", "ARC card (if you have one)"], links: [{ name: "Find a GP (NHS)", url: "https://www.nhs.uk/service-search/find-a-gp" }, { name: "NHS App", url: "https://www.nhs.uk/nhs-app/" }, { name: "Find a dentist (NHS)", url: "https://www.nhs.uk/service-search/find-a-dentist" }] },
  { id: "mental", cat: "Healthcare", icon: "🧠", content: { en: { title: "Mental Health Support", summary: "Free mental health care. Seeking help is strength.", steps: ["Self-refer to NHS Talking Therapies — free CBT, no GP referral needed.", "Freedom from Torture: free therapy for survivors — 020 7697 7777.", "Crisis: Samaritans 116 123 (free 24/7) or text SHOUT to 85258.", "Domestic Abuse: 0808 2000 247 (free, 24/7, all languages)."] } }, cost: "Free", time: "Self-refer or via GP", bring: [], links: [{ name: "NHS Talking Therapies", url: "https://www.nhs.uk/mental-health/talking-therapies-medicine-treatments/talking-therapies-and-counselling/nhs-talking-therapies/" }, { name: "Freedom from Torture", url: "https://www.freedomfromtorture.org" }] },
  { id: "renting", cat: "Housing", icon: "🔑", content: { en: { title: "Renting a Home", summary: "Your rights as a renter. Landlords must accept share codes.", steps: ["Give landlords a Right to Rent share code + your date of birth. They verify online.", "Landlords CANNOT discriminate by nationality — it's unlawful.", "Search: SpareRoom, Rightmove, Zoopla. Filter by distance and budget.", "Maximum deposit is 5 weeks' rent. Must be in a government protection scheme.", "Always get a written tenancy agreement before paying anything.", "⚠ Landlords cannot evict without a court order. Changing locks illegally is a criminal offence."] } }, cost: "Deposit + 1st month", time: "Start searching now", bring: ["Right-to-rent share code"], links: [{ name: "SpareRoom", url: "https://www.spareroom.co.uk" }, { name: "Rightmove", url: "https://www.rightmove.co.uk" }, { name: "Deposit protection (GOV.UK)", url: "https://www.gov.uk/tenancy-deposit-protection" }] },
  { id: "housing-help", cat: "Housing", icon: "🏠", content: { en: { title: "Council Housing & Homelessness Help", summary: "If homeless or at risk, your local council has a legal duty to help. Refugees have powerful legal protections.", steps: ["Contact your local council housing department immediately. You are a priority need as a newly recognised refugee.", "You have a PERMANENT local connection to the council area where your refugee decision was made — this right can NEVER be lost and is critical for your housing application. Moving away from your dispersal area may affect this.", "Apply for the social housing waiting list as early as possible — long waits in most cities, but being on the list is essential.", "Claim UC Housing Element immediately — this helps cover rent in private accommodation while you wait.", "Refugees at Home: free matching service connecting refugees with UK hosts who have a spare room. Especially useful during the move-on period (refugeesathome.org).", "NACCOM: national network of refugee accommodation charities — lists 90+ organisations across the UK (naccom.org.uk).", "Shelter helpline: 0808 800 4444 (free, Mon–Fri 8am–8pm) — specialist housing advice.", "Crisis charity: homelessness services across England, Scotland, and Wales (crisis.org.uk).", "⚠ Your council MUST give you emergency accommodation if you are homeless — do not accept 'we can't help' as an answer."] } }, cost: "Free", time: "Apply immediately", bring: ["Refugee decision letter", "Share code"], links: [{ name: "Find your council (GOV.UK)", url: "https://www.gov.uk/find-local-council" }, { name: "Shelter", url: "https://www.shelter.org.uk" }, { name: "Refugees at Home", url: "https://www.refugeesathome.org" }, { name: "NACCOM", url: "https://naccom.org.uk" }, { name: "Crisis", url: "https://www.crisis.org.uk" }] },
  { id: "move-on", cat: "Housing", icon: "📦", content: { en: { title: "The 56-Day Move-On Period", summary: "Just got refugee status? You have 56 days to leave asylum accommodation and set up your new life.", steps: ["When you receive your refugee decision letter, the 56-day countdown begins immediately. Do not wait — start today.", "IMMEDIATELY apply for Universal Credit online. The 5-week wait starts from your application date — every day of delay costs money. Citizens Advice has a national contract to help newly-recognised refugees apply, with translation available (0800 144 8848).", "Open a bank account the same day — Revolut, Monzo, Starling, or Monese all accept share code + selfie with no fixed address required.", "Apply for your National Insurance number online. You can work while waiting for it to arrive (takes 4–16 weeks).", "Contact your local council housing team immediately. Explain you are a newly recognised refugee. You have a PERMANENT local connection to this council area — this is an irrevocable legal right and key to your housing application.", "If you had your passport surrendered to the Home Office at Croydon or any UKVI office, apply for a Convention Travel Document (CTD) — £75. This is your travel document for any international travel.", "Register with a GP. Download the NHS App. No address, ID, or immigration status check is required.", "Apply for a CitizenCard (£15) for photo ID while you wait for your CTD. Apply at citizencard.com — arrives in 2–3 weeks.", "Get a free SIM card from the National Databank — 40GB/month from Vodafone, free at any library, O2 store, or partner charity.", "Ask your Jobcentre Work Coach about the Flexible Support Fund — up to £300 for deposits, transport, and work clothes.", "Your ASPEN payment card remains usable for 28 days AFTER your asylum support formally ends — keep using it during this grace period.", "If you cannot find housing by day 56, show 'reasonable efforts' to NASS — UC application, council contact, housing search evidence. Support can be extended.", "Free furniture: British Heart Foundation shops, Freecycle.org, Facebook Marketplace 'Free' section, local refugee charities, Emmaus communities.", "After 6 months on UC: apply for a Budgeting Advance (up to £812 for furniture and household items) via your UC journal.", "⚠ Do NOT wait. Start everything on day 1. Every day of delay on Universal Credit is money lost."] } }, cost: "Free", time: "Start immediately — day 1", bring: ["Refugee decision letter", "eVisa / share code details"], links: [{ name: "Apply for UC (GOV.UK)", url: "https://www.gov.uk/universal-credit/how-to-claim" }, { name: "Citizens Advice", url: "https://www.citizensadvice.org.uk" }, { name: "Shelter — move-on help", url: "https://www.shelter.org.uk" }, { name: "Refugees at Home (spare rooms)", url: "https://www.refugeesathome.org" }, { name: "NACCOM refugee housing network", url: "https://naccom.org.uk" }, { name: "Freecycle (free furniture)", url: "https://www.freecycle.org" }] },
  { id: "work-rights", cat: "Work", icon: "💼", content: { en: { title: "Your Right to Work", summary: "Know your specific work rights and restrictions before starting any job.", steps: ["Refugees & ILR holders: NO restrictions. Any job, any hours.", "Skilled Worker visa: must work for the named sponsor employer only.", "Family visa: usually full work rights — verify on your eVisa.", "Student visa: max 20hrs/week during term. Full-time only in vacations.", "EU Settled Status: full unrestricted work rights.", "Give employers a Right to Work share code before your start date."] } }, cost: "Free", time: "Check before any job", bring: ["Right-to-work share code"], links: [{ name: "Prove right to work (GOV.UK)", url: "https://www.gov.uk/prove-right-to-work" }, { name: "Skilled Worker visa rules (GOV.UK)", url: "https://www.gov.uk/skilled-worker-visa" }] },
  { id: "permission-to-work", cat: "Work", icon: "🔓", content: { en: { title: "Permission to Work as an Asylum Seeker", summary: "Waited 12+ months since your asylum claim? You may already qualify — even if you've been in the inadmissibility process. Rules expand further from 26 March 2026.", steps: ["You can apply for Permission to Work if: (1) you have waited 12 or more months for an initial Home Office decision on your asylum claim, AND (2) the delay is not your fault (e.g. you have cooperated fully and not caused delays yourself).", "⚠️ CRITICAL — when does the 12-month clock start? It starts from the date you FIRST CLAIMED ASYLUM — NOT from when your claim moved to 'substantive consideration'. Months spent in the inadmissibility process (e.g. Rwanda/safe third country route) still count toward your 12 months.", "Inadmissibility & Permission to Work: If you claimed asylum 12+ months ago but your claim spent time in the inadmissibility process, you may ALREADY be eligible. Example: claimed 14+ months ago and in inadmissibility for 6 of those months — the 12-month clock has still been running since your original claim date. Raise this with your solicitor immediately.", "⭐ IMPORTANT CHANGE FROM 26 MARCH 2026: The eligibility rules are expanding significantly. Most asylum seekers don't know about this yet.", "BEFORE 26 March 2026: Permission to Work is restricted to jobs on the Immigration Salary List (formerly the Shortage Occupation List). This covers shortage occupations including civil engineering, nursing, teaching, coding, and other high-demand roles.", "FROM 26 March 2026 onwards: Permission to Work extends to all RQF Level 6+ (graduate-level) roles listed in Appendix Skilled Occupations. This opens up most degree-level and professional careers. Examples of newly eligible roles: Civil/structural engineer, Software developer, Project manager, Teacher, Nurse, Accountant, Social worker, Surveyor, Business analyst, and interpreter roles (e.g. NRPSI registered — nrpsi.org.uk).", "Self-employment is NOT allowed — you must be employed by a named employer. Volunteering with an organisation's permission is allowed.", "Your ARC card will be updated to show 'Permitted to Work' with the restriction category noted on the front. Show this to your employer.", "How to apply: ask your solicitor to submit the application on your behalf, or apply directly to the Home Office. There is NO application fee.", "Processing time: typically 2–8 weeks. There is no premium service — all applications are treated equally.", "⚠ If your solicitor has not mentioned this to you, raise it immediately. This change on 26 March 2026 opens up an enormous range of jobs you would not previously have been eligible for."] } }, cost: "Free", time: "2–8 weeks processing", bring: ["ARC card", "Evidence of 12+ months wait (Home Office correspondence)", "Solicitor contact details (recommended)"], links: [{ name: "Permission to Work — GOV.UK guidance", url: "https://www.gov.uk/government/publications/handling-applications-for-permission-to-take-employment-instruction/permission-to-work-and-volunteering-for-asylum-seekers-accessible" }, { name: "Immigration Salary List (GOV.UK)", url: "https://www.gov.uk/guidance/immigration-salary-list" }, { name: "Appendix Skilled Occupations (GOV.UK)", url: "https://www.gov.uk/guidance/immigration-rules/immigration-rules-appendix-skilled-occupations" }, { name: "NRPSI — Register of Public Service Interpreters", url: "https://www.nrpsi.org.uk" }] },
  { id: "employment-rights", cat: "Work", icon: "⚖️", content: { en: { title: "Employment Rights", summary: "Every worker has legal rights from day one regardless of nationality.", steps: ["National Living Wage (21+): £12.71/hr from April 2026 (was £12.21). Illegal to pay less.", "Day one rights: 28 days paid leave, written contract, rest breaks.", "Statutory Sick Pay: £118.75/week after 4 consecutive sick days.", "After 2 years: unfair dismissal protection.", "Discrimination by race, religion, or nationality is illegal. ACAS: 0300 123 1100.", "New: Fair Work Agency launches April 2026 — stronger enforcement of wage and holiday rights."] } }, cost: "Free", time: "Know before you start", bring: [], links: [{ name: "Minimum wage rates (GOV.UK)", url: "https://www.gov.uk/national-minimum-wage-rates" }, { name: "ACAS (free workplace advice)", url: "https://www.acas.org.uk" }, { name: "Citizens Advice work rights", url: "https://www.citizensadvice.org.uk/work/" }] },
  { id: "schools", cat: "Family & Kids", icon: "🏫", content: { en: { title: "Children & Schools", summary: "All children aged 5–16 have the right to a free school place.", steps: ["Contact your local council school admissions team immediately.", "Schools CANNOT refuse children who don't speak English.", "Free EAL (English as Additional Language) support in all state schools.", "Free school meals if parents receive UC.", "Free childcare: 15–30 hours/week for ages 3–4."] } }, cost: "Free", time: "Within 20 school days", bring: ["Immunisation records (if available)"], links: [{ name: "Find your council (GOV.UK)", url: "https://www.gov.uk/find-local-council" }, { name: "Free school meals (GOV.UK)", url: "https://www.gov.uk/apply-free-school-meals" }, { name: "Free childcare (GOV.UK)", url: "https://www.gov.uk/get-childcare" }] },
  { id: "ctd", cat: "Documents & ID", icon: "🛂", content: { en: { title: "Convention Travel Document (CTD)", summary: "For recognised refugees who cannot use their home country passport.", steps: ["If you're a recognised refugee, you can apply for a CTD to travel internationally.", "Apply online. Cost: £75. Processing: usually 1–3 months.", "The CTD allows travel to most countries except your country of origin.", "⚠ NEVER travel to your country of origin — this can result in loss of refugee status.", "Since 11 March 2026, Home Office travel documents (CTD, Certificate of Travel) automatically link to your UKVI account — airlines and border staff now verify digitally. No separate letter needed.", "You can also apply for a Certificate of Travel if you have Humanitarian Protection.", "Get passport photos at any Post Office (about £12) or use a phone app."] } }, cost: "£75", time: "1–3 months", bring: ["UKVI account", "Passport-size photos", "Completed form"], links: [{ name: "Apply for travel document (GOV.UK)", url: "https://www.gov.uk/apply-home-office-travel-document" }, { name: "Passport photo rules (GOV.UK)", url: "https://www.gov.uk/photos-for-passports" }] },
  { id: "citizen-card", cat: "Documents & ID", icon: "🪪", content: { en: { title: "CitizenCard — Photo ID for £15", summary: "Government-backed PASS-accredited photo ID. No passport needed.", steps: ["A CitizenCard is a UK government-backed PASS-accredited photo ID card.", "Accepted as proof of age and identity in shops, banks, pubs, Post Offices, most organisations.", "Apply online. Cost: £15. Arrives in 2–3 weeks.", "You need: a passport-size photo, proof of address, and any document showing your date of birth.", "No passport? A Home Office decision letter + proof of address is enough.", "This is NOT an immigration document — use your share code for work/rent.", "Most affordable photo ID for anyone without a passport."] } }, cost: "£15", time: "2–3 weeks", bring: ["Photo", "Proof of address", "Any age proof"], links: [{ name: "Apply for CitizenCard", url: "https://www.citizencard.com" }, { name: "PASS scheme info", url: "https://www.pass-scheme.org.uk" }] },
  { id: "driving", cat: "Documents & ID", icon: "🚗", content: { en: { title: "Driving, Licence &amp; Buying a Vehicle", summary: "Get a UK licence, buy a car, e-bike, or scooter — everything a new immigrant needs to know.", steps: ["You can drive on a valid foreign licence for 12 months from when you became a UK resident.", "After 12 months you MUST get a UK licence or stop driving. Some countries have exchange agreements — swap without a test. Check GOV.UK. Ethiopia is NOT on the exchange list — you must take theory + practical tests.", "Apply for a UK provisional licence: £34 online, £43 by post. Need passport or share code + proof of address. With a provisional: supervised driving only (supervisor needs full UK licence 3+ years), L plates required.", "Theory test: £23. Multiple choice (50 questions, need 43/50) + hazard perception video (14 clips, need 44/75). Both parts in one sitting — results immediate. Pass valid 2 years.", "Practical driving test: £62 weekday / £75 evening or weekend. Lessons cost £25–£40/hour. Some councils fund lessons for refugees on UC — ask your Jobcentre Work Coach about the Flexible Support Fund.", "── BUYING A CAR ──", "You do NOT need a credit history to buy a car outright with cash. Budget used cars start from £500–£1,500 on AutoTrader, Gumtree, Facebook Marketplace. Always check the free MOT history at gov.uk/check-mot-history before viewing.", "Before buying any used car, run an HPI check (~£10 at hpicheck.com). This confirms the car is not stolen, has no outstanding finance, and has not been written off. Never skip this step — it is the most important check.", "Car insurance is required by law before driving. As a new driver or new UK resident, expect high quotes (£1,500–£3,000+/year). Compare at MoneySuperMarket, GoCompare, or CompareTheMarket. Adding an experienced named driver lowers the premium.", "Car finance with no UK credit history: lenders like Zuto and CarFinance247 specialise in thin-credit applicants. A larger deposit (£500–£1,000+) helps. Avoid 'no credit check' deals — APR can exceed 40%. Hire Purchase (HP) or Personal Contract Purchase (PCP) are the two main finance types. HP = you own the car at the end. PCP = lower monthly payments but a large final 'balloon' payment or hand-back.", "Buying from a dealer: you get Consumer Rights Act protection — dealer must fix faults within 30 days. Private sale: 'buyer beware' — fewer legal protections, but cars are cheaper. Always test drive and bring a mechanic if you can.", "Road tax (Vehicle Excise Duty): most petrol cars cost £190–£620/year. Fully electric cars are currently free. Pay at gov.uk/vehicle-tax. It is NOT transferable — always check that VED is current before driving off.", "── E-BIKES ──", "Electric bikes (e-bikes) are FULLY LEGAL with no licence, no insurance, no registration needed — as long as the motor is under 250W and stops assisting at 15.5mph. This is the legal standard for all e-bikes sold in UK shops. You can ride from day one.", "E-bikes cost £300–£2,000 new. Budget options: Eskute, Carrera, Halfords own-brand. Mid-range: Ribble, Forme. Check Gumtree and Facebook Marketplace for used e-bikes from £150. Check battery health — replacement batteries cost £150–£400.", "City e-bike hire: Lime, Forest, Beryl, and HumanForest operate dockless e-bikes in many UK cities. Download the app, add a payment card, and ride — no licence or deposit required. Typically £1–£2 to unlock + £0.15–£0.20/minute.", "── E-SCOOTERS ──", "Private e-scooters are ILLEGAL to ride on public roads, pavements, or cycle lanes in the UK. You can only ride one on private land with the landowner's permission. If caught riding one on the road: £300 fine, 6 points on licence, and seizure.", "Rental e-scooters from city trial schemes (Lime, Voi, Tier, Dott) ARE legal in participating cities — you must have a provisional or full driving licence to rent. Check if your city has a scheme at gov.uk/guidance/e-scooter-trials-guidance-for-users.", "── KEY RULES ──", "Every car or motorbike needs: valid insurance (illegal to drive without), current MOT if over 3 years old (book at gov.uk/book-mot-test), and paid road tax. Check any vehicle's status free at gov.uk/check-vehicle-information.", "SORN (Statutory Off Road Notification): if you buy a car but don't insure it immediately, declare SORN at gov.uk/make-a-sorn — otherwise you face an automatic fine. SORN means you cannot drive or park it on a public road.", "Speed limits to know: 20mph in most residential streets (many UK cities), 30mph in towns (unless signed otherwise), 60mph single carriageway, 70mph motorway. Speed cameras are very common — fines start at £100 + 3 points."] } }, cost: "£34–£43 provisional + test fees", time: "Varies", bring: ["Foreign licence (if any)", "Passport or share code", "Proof of address"], links: [{ name: "Apply for provisional (GOV.UK)", url: "https://www.gov.uk/apply-first-provisional-driving-licence" }, { name: "Exchange foreign licence (GOV.UK)", url: "https://www.gov.uk/exchange-foreign-driving-licence" }, { name: "Designated countries list (GOV.UK)", url: "https://www.gov.uk/driving-nongb-licence" }, { name: "Book theory test (GOV.UK)", url: "https://www.gov.uk/book-theory-test" }, { name: "Book practical test (GOV.UK)", url: "https://www.gov.uk/book-driving-test" }, { name: "Check MOT history free (GOV.UK)", url: "https://www.gov.uk/check-mot-history" }, { name: "Check vehicle tax &amp; MOT (GOV.UK)", url: "https://www.gov.uk/check-vehicle-information" }, { name: "Pay road tax (GOV.UK)", url: "https://www.gov.uk/vehicle-tax" }, { name: "HPI Check — used car history", url: "https://www.hpicheck.com" }, { name: "AutoTrader — Buy &amp; sell cars", url: "https://www.autotrader.co.uk" }, { name: "CarFinance247 — no/thin credit", url: "https://www.carfinance247.co.uk" }, { name: "E-scooter trial cities (GOV.UK)", url: "https://www.gov.uk/guidance/e-scooter-trials-guidance-for-users" }] },
  { id: "proof-address", cat: "Documents & ID", icon: "📮", content: { en: { title: "Proof of Address", summary: "Get accepted proof even without a fixed home.", steps: ["Accepted documents: UC letter, HMRC letter, utility bill, bank statement (within 3 months).", "No fixed address? A letter from your hostel or support organisation works.", "Register to vote — the confirmation letter counts as proof of address.", "Royal Mail PO Box from £12 for 6 months gives you a stable mailing address."] } }, cost: "Free–£12", time: "1–5 days", bring: [], links: [{ name: "Register to vote (GOV.UK)", url: "https://www.gov.uk/register-to-vote" }, { name: "Royal Mail PO Box", url: "https://www.royalmail.com/receiving/po-box" }] },
  { id: "travel", cat: "Travel", icon: "✈️", content: { en: { title: "Travelling Abroad", summary: "How to travel now that BRPs are gone.", steps: ["Travel with your passport linked to your eVisa in UKVI. Link it BEFORE you travel.", "Since June 2025, expired BRPs are NOT accepted for travel.", "Refugees without a passport: apply for a Convention Travel Document (see CTD guide).", "⚠ Refugees: NEVER travel to your country of origin. Risk losing your status.", "Since 11 March 2026, Home Office travel documents auto-link to your UKVI account — no need to carry a separate letter.", "EU citizens: your EU passport is still valid for EU travel."] } }, cost: "CTD £75 if needed", time: "Apply 3+ months ahead", bring: ["Passport linked to UKVI"], links: [{ name: "Travel with eVisa (GOV.UK)", url: "https://www.gov.uk/evisa/travel-with-evisa" }, { name: "Apply for travel document (GOV.UK)", url: "https://www.gov.uk/apply-home-office-travel-document" }] },
  { id: "ilr", cat: "Settle & Stay", icon: "🏅", content: { en: { title: "Indefinite Leave to Remain (ILR)", summary: "Permanent UK residence — the biggest milestone. Refugees use form SET(P) which is completely FREE.", steps: ["Refugees: apply using form SET(P) after 5 years of lawful residence. This form has NO FEE — saving you £2,885 compared to other routes.", "Standard routes (Skilled Worker, Family, etc.) pay £2,885. As a refugee, you are exempt from this fee.", "⚠ 2025 white paper proposals may change settlement timelines. Check GOV.UK regularly.", "Pass the Life in the UK Test (£50) — 24 questions on UK history, culture, laws. Most people pass with 2–3 weeks of free online practice.", "Prove English at level B1 — ESOL qualification, degree from a UK university, or a Secure English Language Test (SELT).", "Keep ALL documents for 5+ years: payslips, P60s, bank statements, tenancy agreements, travel records.", "After ILR, apply for British citizenship after just 1 year — requires English language, Life in the UK Test, and good character.", "Citizenship by naturalisation costs £1,500 but opens a UK passport, visa-free travel, and full civic rights.", "⚠ Avoid any absence from the UK exceeding 180 days in a year — this can break continuity and delay your ILR."] } }, cost: "FREE via SET(P) for refugees / £2,885 other routes", time: "After 5 years of residence", bring: ["5 years of documents (payslips, bank statements, tenancy)", "Passport or travel document"], links: [{ name: "ILR information (GOV.UK)", url: "https://www.gov.uk/indefinite-leave-to-remain" }, { name: "SET(P) form for refugees (GOV.UK)", url: "https://www.gov.uk/settle-in-the-uk/y/you-have-refugee-status-or-humanitarian-protection" }, { name: "Life in the UK Test", url: "https://www.gov.uk/life-in-the-uk-test" }, { name: "Apply for British citizenship (GOV.UK)", url: "https://www.gov.uk/becoming-a-british-citizen" }] },
  { id: "safety", cat: "Community", icon: "🛡", content: { en: { title: "Staying Safe", summary: "Know your rights, avoid scams, get help. The UK system has real protections for you.", steps: ["Police and immigration are SEPARATE. The police have an official firewall policy — they do NOT share information with the Home Office or immigration enforcement. You can report crimes, seek help, and be a witness without fear of immigration action.", "Police: 999 for emergencies, 101 for non-emergencies. Always call — your safety is protected by UK law regardless of your immigration status.", "Modern Slavery Helpline: 0800 0121 700 — free, 24/7, anonymous. If someone is controlling your movements, work, or money, this is illegal and they can help.", "If someone holds your passport, charges you for housing/work, or controls your bank account — this is modern slavery. Call 0800 0121 700.", "Domestic Abuse: 0808 2000 247 — free, 24/7, all languages. Safehouses are available — you will not be deported for leaving an abusive situation.", "Immigration scams: NEVER pay unregistered 'immigration consultants'. Always check the OISC register at gov.uk/find-an-immigration-adviser. Unregistered advice is a criminal offence.", "Online scams: job offers requiring payment upfront, 'fast track' visa services, requests for your share code — all scams. Report to Action Fraud: 0300 123 2040.", "Housing scams: landlords cannot demand more than 5 weeks' deposit. Never pay before viewing a property in person.", "⚠ Keep copies of all your important documents — decision letter, eVisa screenshot, NI number — in a secure app like Google Drive."] } }, cost: "Free", time: "Read now", bring: [], links: [{ name: "Find immigration adviser (GOV.UK)", url: "https://www.gov.uk/find-an-immigration-adviser" }, { name: "Modern Slavery Helpline", url: "https://www.modernslaveryhelpline.org" }, { name: "Action Fraud (report scams)", url: "https://www.actionfraud.police.uk" }] },
  { id: "community", cat: "Community", icon: "🤝", content: { en: { title: "Community & Social Life", summary: "Build connections and find support near you.", steps: ["Libraries: free internet, books, events, language cafés, computer access.", "Mosques, churches, temples, gurdwaras: community support regardless of your faith.", "Volunteering builds UK experience and references. Try do-it.org.", "Refugee Council: 0808 196 7272.", "Citizens Advice: free help with any issue you're facing."] } }, cost: "Free", time: "Start today", bring: [], links: [{ name: "Do-it volunteering", url: "https://www.do-it.org" }, { name: "Citizens Advice", url: "https://www.citizensadvice.org.uk" }, { name: "Refugee Council", url: "https://www.refugeecouncil.org.uk" }] },
  { id: "volunteering", cat: "Community", icon: "🙋", content: { en: { title: "Volunteering While Waiting for Your Decision", summary: "As an asylum seeker without permission to work, volunteering is the most important thing you can do. Start now — don't wait for your decision.", steps: ["✅ Volunteering is ALWAYS allowed — there are no restrictions on volunteering for asylum seekers. You do not need permission from the Home Office.", "The work must be genuinely voluntary: no obligation, no contract, you can stop any time. It must be for a registered charity or public body — not a private company.", "You can receive expenses only (travel, meals) — no payment or wages. Receiving payment would count as working without permission.", "Why volunteering matters: Building UK references, networks, and experience is essential for when you get your decision or Permission to Work. Volunteering with organisations in your field — engineering, healthcare, legal, construction, education, or any sector — demonstrates commitment and builds trust. UK employers hire people they know.", "Find roles: do-it.org (largest volunteering database — search by skill and location), Reach Volunteering (reachvolunteering.org.uk) specialises in skilled and professional volunteer roles.", "Construction and housing: Habitat for Humanity UK (habitatforhumanity.org.uk) — hands-on construction volunteering, perfect for civil engineering backgrounds.", "Advice and support: your local Citizens Advice bureau recruits volunteer advisers — excellent for building UK legal and welfare knowledge.", "REMA — Refugee Employability & Mentoring Alliance: specialist employability support and mentoring for refugees and asylum seekers. Contact via remauk.org.", "Mentoring: ICE (Institution of Civil Engineers) accepts volunteer mentees through their Refugee Support programme — contact ICE Refugee Support now at ice.org.uk/about-ice/what-we-do/social-mobility/refugee-support/. Do not wait for your decision.", "⭐ Every week of UK volunteering is a week of UK experience on your CV, a UK reference, and a UK network contact. Start today."] } }, cost: "Free", time: "Start immediately", bring: [], links: [{ name: "Do-it volunteering", url: "https://www.do-it.org" }, { name: "Reach Volunteering (skilled roles)", url: "https://reachvolunteering.org.uk" }, { name: "Habitat for Humanity UK (construction)", url: "https://www.habitatforhumanity.org.uk/volunteer/" }, { name: "ICE Refugee Support (engineers)", url: "https://www.ice.org.uk/about-ice/what-we-do/social-mobility/refugee-support/" }, { name: "REMA (Refugee Employability & Mentoring Alliance)", url: "https://remauk.org" }, { name: "GOV.UK — volunteering as an asylum seeker", url: "https://www.gov.uk/government/publications/handling-applications-for-permission-to-take-employment-instruction/permission-to-work-and-volunteering-for-asylum-seekers-accessible" }] },
  { id: "esol-education", cat: "Community", icon: "📚", content: { en: { title: "Free ESOL & Education While Waiting", summary: "ESOL classes are free for all asylum seekers. Use your waiting time to build qualifications and skills — no decision needed.", steps: ["ESOL (English for Speakers of Other Languages) classes are FREE for all asylum seekers — no waiting period, no conditions, and no need to have a decision on your claim.", "Your ARC card is your proof of eligibility for fee remission at any college. Show it when enrolling. You cannot be charged for ESOL if you are an asylum seeker.", "Find ESOL classes: local Further Education (FE) colleges (the biggest providers), refugee charities (e.g. Refugee Council, STAR, local groups), and your local council adult education service. Search 'ESOL classes near me' or ask your local library.", "Higher education — Sanctuary Scholarships: over 80 UK universities offer sanctuary scholarships open to asylum seekers (not only recognised refugees). Edinburgh, Warwick, Bristol, and UCL are among them — many cover full tuition plus a living bursary. Search the STAR network scholarship list at star-network.org.uk.", "Recognition of Prior Learning (RPL): if you hold a degree or professional qualification, some UK universities will assess your existing learning and award credit toward a UK qualification. This can shorten or top up a degree. Ask admissions teams specifically about RPL or credit transfer.", "Free online learning while you wait: OpenLearn (open.edu/openlearn — free, no registration), FutureLearn (futurelearn.com — many free courses), and Coursera (coursera.org — audit most courses free). Use this time to build a UK-relevant portfolio of learning.", "Google Career Certificates are free (or heavily subsidised) for eligible learners and are recognised by UK employers — Data Analytics, Project Management, UX Design, IT Support, Cybersecurity. Each takes 3–6 months online at your own pace.", "PRINCE2 Foundation: the study materials are freely available online; the exam costs ~£300 when you're ready to sit it. This qualification is widely recognised by UK project management employers.", "CSCS card theory preparation: the CITB CSCS Health, Safety and Environment test costs £26 to sit. Use the free CSCS revision app to prepare now so you can sit it as soon as you have the right to work.", "⭐ Building qualifications, certificates, and learning evidence while waiting transforms your CV and demonstrates commitment to UK employers. Start now — none of this requires a work permit."] } }, cost: "Free (ESOL) — exam fees apply for some certifications", time: "Start immediately", bring: ["ARC card (for ESOL fee remission)"], links: [{ name: "Find ESOL classes (GOV.UK)", url: "https://www.gov.uk/find-a-community-support-group-or-organisation" }, { name: "OpenLearn (free courses)", url: "https://www.open.edu/openlearn/" }, { name: "FutureLearn", url: "https://www.futurelearn.com" }, { name: "Google Career Certificates", url: "https://grow.google/intl/uk_ALL/google-career-certificates/" }, { name: "STAR — University Sanctuary Scholarships", url: "https://star-network.org.uk/access-to-university/scholarships/list/" }, { name: "Coursera (audit free)", url: "https://www.coursera.org" }] },
  { id: "re-qualify", cat: "Work", icon: "🎓", content: { en: { title: "Recognise Your Qualifications", summary: "Your overseas degree and professional credentials can be recognised in the UK — often for free.", steps: ["UK ENIC (formerly UK NARIC): get a Statement of Comparability for your overseas degree — £49. Accepted by employers, universities, and professional bodies across the UK.", "Refugees without original documents: email refugee@ecctis.com — reduced-cost or waived assessment available. Your institution may also provide a replacement certificate.", "Breaking Barriers Reaccreditation Programme: free professional assessment, mentoring, and liaison with UK regulatory bodies. Covers engineering, healthcare, teaching, law, finance, and trades. Apply at breaking-barriers.co.uk.", "RefuAid interest-free loans: up to £10,000 to cover exam fees, registration costs, course materials for re-qualifying. Zero interest, repayable once you're earning. Access via RefuAid's partner network at refuaid.org.", "Civil Engineers (BSc/BEng/MEng): ICE Refugee Support programme — free mentoring and chartership (MICE → CEng) pathway. The Engineering Council registers all UK engineers. Target CEng status within 3–5 years for £50K–£80K+ salaries.", "Chartered Surveyors &amp; Valuers (RICS): if you have a background in property valuation, real estate, construction management, or quantity surveying, the RICS Assessment of Professional Competence (APC) is your route to MRICS status — the internationally recognised gold standard for UK property professionals. Breaking Barriers Reaccreditation supports RICS candidates. APC fees: £305–£625 depending on route. Once MRICS qualified, salary range: £40K–£80K+. Candidates from countries with RICS-accredited programmes (including Addis Ababa University for some degrees) may qualify for partial credit assessment. Contact RICS directly at rics.org.", "Interpreters &amp; Community Translators (Amharic, Somali, Tigrinya, Arabic, Dari, Ukrainian): rare-language public service interpreters are in critical shortage across the NHS, courts, police, and social services. The DPSI (Diploma in Public Service Interpreting), awarded by the Chartered Institute of Linguists (ciol.org.uk), is the professional qualification recognised across public sector contracts. Once qualified, register on NRPSI (nrpsi.org.uk). Rates: NHS/council £25–£40/hour, courts £30–£55/hour, police £35–£50/hour. This is an excellent self-employed or part-time income stream alongside other work. DPSI exam fee: approximately £260–£400.", "For an MBA: APM (Association for Project Management) and CMI (Chartered Management Institute) recognise business qualifications. A Chartered Manager Degree Apprenticeship is a free route to CMI Level 6.", "Doctors: GMC registration + PLAB Part 1 & 2 exams. Many NHS trusts fund OSCE exams for overseas doctors. Breaking Barriers healthcare track provides mentors.", "Nurses: NMC registration + OSCE (Objective Structured Clinical Examination) for overseas-trained nurses. NHS trusts commonly fund this.", "Teachers: qualified teacher status via School Direct or Assessment Only route. UK ENIC recognition helps. Contact the DfE and Refugee Education UK.", "Lawyers: Solicitors Qualification Examination (SQE) is the new route. Some law firms and charities (e.g. Refugee Legal Aid) run bursary programmes.", "⚠ Never pay unregistered agencies to 'certify' your qualifications. Use only UK ENIC, your UK professional body, or GOV.UK."] } }, cost: "£49 UK ENIC + professional body fees (often funded)", time: "Weeks to years depending on profession", bring: ["Degree certificate (original or copy)", "Academic transcripts", "Professional registration certificates"], links: [{ name: "UK ENIC Statement of Comparability", url: "https://www.enic.org.uk/Qualifications/SOC/Default.aspx" }, { name: "Breaking Barriers Reaccreditation", url: "https://breaking-barriers.co.uk/refugee-support/reaccreditation/" }, { name: "RefuAid Interest-Free Loans", url: "https://www.refuaid.org" }, { name: "ICE Refugee Support (Engineers)", url: "https://www.ice.org.uk/about-ice/what-we-do/social-mobility/refugee-support/" }, { name: "Engineering Council (UK)", url: "https://www.engc.org.uk" }, { name: "RICS — Chartered Surveyor (APC)", url: "https://www.rics.org/careers-in-surveying/become-a-member" }, { name: "NRPSI — Register of Public Service Interpreters", url: "https://www.nrpsi.org.uk" }, { name: "CIOL — Chartered Institute of Linguists (DPSI)", url: "https://www.ciol.org.uk/dpsi" }] },
  { id: "family-reunion", cat: "Family & Kids", icon: "👨‍👩‍👧", content: { en: { title: "Family Reunion", summary: "Bring your immediate family to the UK. Know the current rules.", steps: ["⚠ The refugee family reunion route was PAUSED as of 4 September 2025. New rules were expected Spring 2026 — check gov.uk regularly for the latest status, as rules may have changed.", "During the pause: your spouse/partner and children under 18 must apply through standard family visa routes. These cost £1,538+ per person.", "A refugee family reunion application was previously free — the pause is temporary. Once new rules are published, apply immediately.", "RefuAid interest-free loans can help cover family reunion costs including legal fees and travel expenses. Contact via refuaid.org.", "Legal aid is available for refugee family reunion cases — contact a Legal Aid solicitor via the Law Centres Network (lawcentres.org.uk).", "Family tracing help: the Refugee Council (0808 196 7272) and the British Red Cross (redcross.org.uk) both provide family tracing services.", "Keep evidence of your family relationship: photos, messages, marriage/birth certificates (or sworn statements if documents are unavailable).", "⚠ NEVER travel to your country of origin to collect family members — this risks your refugee status.", "⚠ Family reunion is paused but NOT abolished. Your right will return under new rules — prepare your documents now."] } }, cost: "Free (refugee route) / £1,538+ per person (standard visa route)", time: "3–12+ months once route reopens", bring: ["Proof of family relationship", "Evidence of refugee status"], links: [{ name: "Refugee family reunion (GOV.UK)", url: "https://www.gov.uk/uk-family-visa" }, { name: "Refugee Council — family reunion", url: "https://www.refugeecouncil.org.uk/information/refugee-asylum-facts/family-reunion/" }, { name: "Law Centres Network (legal aid)", url: "https://www.lawcentres.org.uk" }, { name: "RefuAid loans", url: "https://www.refuaid.org" }] },
  { id: "legal-help", cat: "Community", icon: "⚖️", content: { en: { title: "Free Legal Advice", summary: "Free legal help is available for immigration, housing, employment, and more. You have the right to legal aid — this guide shows you where to find it.", steps: ["Legal aid is FREE for most immigration and asylum cases. You do NOT need to pay a solicitor for asylum appeals, bail hearings, or immigration tribunal hearings. Check if you qualify at gov.uk/legal-aid.", "Find an OISC-registered immigration adviser using the official GOV.UK search (gov.uk/find-an-immigration-adviser). OISC-registered advisers are regulated and trustworthy. Never use an unregulated 'immigration consultant' — it is illegal to charge for immigration advice unless registered.", "Law Centres: free specialist legal advice on employment, housing, welfare benefits, and immigration. Find your nearest at lawcentres.org.uk.", "Citizens Advice: free advice on any legal issue — benefits, housing, employment, debt, family. Walk in or call 0800 144 8848. Translation services available.", "Shelter: free housing legal advice online, by phone (0808 800 4444), or in person. Specialist housing lawyers at no cost.", "Asylum Aid: free specialist legal help for complex asylum cases, particularly for women and unaccompanied children — asylumaid.org.uk.", "UNHCR UK: if you believe your rights are being violated in the asylum process, contact the UNHCR at unhcr.org/uk.", "Employment rights: ACAS (Advisory, Conciliation and Arbitration Service) provides free employment rights advice — acas.org.uk or 0300 123 1100. Free for all workers.", "Housing legal rights: if you are being illegally evicted, your landlord has changed the locks, or you are being harassed, call Shelter immediately (0808 800 4444). These are criminal offences.", "⚠ Never pay anyone claiming to offer immigration advice who is not OISC-registered or a solicitor. Fake immigration advisers are common and charge thousands for work that should be free. If something goes wrong, report to the OISC at oisc.gov.uk."] } }, cost: "Free", time: "Legal aid available immediately", bring: ["Any letters or documents relating to your case"], links: [{ name: "Check if you qualify for legal aid (GOV.UK)", url: "https://www.gov.uk/legal-aid" }, { name: "Find OISC immigration adviser (GOV.UK)", url: "https://www.gov.uk/find-an-immigration-adviser" }, { name: "Law Centres Network", url: "https://www.lawcentres.org.uk" }, { name: "Citizens Advice", url: "https://www.citizensadvice.org.uk" }, { name: "Shelter — housing legal help", url: "https://www.shelter.org.uk" }, { name: "Asylum Aid", url: "https://www.asylumaid.org.uk" }, { name: "ACAS — employment rights", url: "https://www.acas.org.uk" }] },
  { id: "aspen-card", cat: "Asylum Process", icon: "💳", content: { en: { title: "Asylum Support & Your ASPEN Card", summary: "How Section 95 support works, what your ASPEN card covers, and what to do if things go wrong.", steps: ["Section 95 support is provided by the Home Office to asylum seekers who would otherwise be destitute. It has two parts: accommodation (provided directly) and a weekly cash payment loaded onto your ASPEN card.", "The standard Section 95 rate for 2025/26 is £49.18 per week for a single adult. Higher rates apply if you have dependent children. This is your entire weekly living allowance.", "Payments are loaded onto your ASPEN card weekly. The day depends on your area — most areas pay on Mondays, some on Wednesdays. Check your support letter for your area's payment day.", "Your ASPEN card works like a Visa prepaid card. You can use it anywhere that accepts Visa — supermarkets, pharmacies, clothing shops, and transport. You do NOT need to explain what it is.", "Older ASPEN cards CANNOT be used at ATMs to withdraw cash. Newer cards may allow limited cashback at supermarket tills (usually £10–£20). If you need cash, ask the cashier for cashback when buying something.", "There is no way to top up your ASPEN card. The amount loaded is fixed by the Home Office. If you feel the amount is wrong, contact Migrant Help on 0808 8010 503 (free helpline).", "If you lose your ASPEN card, report it immediately to Migrant Help: 0808 8010 503 (free, 24/7). A replacement will be issued. Do not delay — your payments may be suspended until the new card arrives.", "Your ASPEN card is intended to cover: food and drink, clothing, toiletries and personal hygiene items, and travel within your local reporting area. It does NOT cover rent — your accommodation is provided separately by the Home Office as part of Section 95 support.", "Section 4 support is different. If your asylum claim has been refused but you cannot safely return to your home country, you may qualify for Section 4 support. Section 4 provides accommodation and an Azure card (similar to ASPEN) instead of cash. Contact Migrant Help to apply.", "Maternity payment: if you are pregnant, you can apply for a one-off £300 maternity grant in addition to your weekly support. Apply through Migrant Help (0808 8010 503) — this is not automatic, you must ask.", "⚠ Never give your ASPEN card or its PIN to anyone else. Never pay anyone to 'manage' your ASPEN payments. If anyone asks, it is a scam."] } }, cost: "Free (provided by Home Office)", time: "Weekly payments while claim is active", bring: ["ASPEN card", "Home Office support letter"], links: [{ name: "Asylum support (GOV.UK)", url: "https://www.gov.uk/asylum-support" }, { name: "Section 4 support (GOV.UK)", url: "https://www.gov.uk/asylum-support/section-4-support" }, { name: "Migrant Help (0808 8010 503)", url: "https://www.migranthelp.org" }, { name: "Asylum support rates (GOV.UK)", url: "https://www.gov.uk/government/publications/asylum-support-asylum-seekers-bank-accounts-and-nass-35" }] },
  { id: "housing-broker", cat: "Work", icon: "🏘️", content: { en: { title: "Become a Community Housing Broker", summary: "Help Ethiopian, Eritrean, and other refugees find housing in the UK — and build an income doing it. No licence required to start.", steps: ["Estate agency in the UK is almost entirely UNREGULATED. There is no legal requirement to hold a licence to introduce a tenant to a landlord or a buyer to a seller. This means that as soon as you have the right to work (refugee status or Permission to Work), you can begin operating as a housing intermediary immediately.", "What you CAN legally do without a licence: introduce prospective tenants or buyers to landlords or sellers, translate between parties who don't share a language, advise community members on what to look for in a rental or property, negotiate terms on behalf of someone, and charge a finder's fee or referral fee for successful introductions.", "What requires caution or a licensed agent: collecting rent on behalf of a landlord (you become a 'letting agent' and must be registered with a Property Redress Scheme — cost ~£200/year), holding client money (e.g. deposits) — you MUST be registered and have Client Money Protection insurance, and formally advertising yourself as a licensed or regulated agent when you are not.", "Getting started — Phase 1 (free, no status required): Help community members for free while building your reputation and knowledge. Learn what landlords want, what tenants need, how viewings work, what an AST (Assured Shorthold Tenancy) agreement contains. This builds trust, which is your most valuable asset.", "Getting started — Phase 2 (after you have right to work): Start charging. Finder's fee model: charge either the landlord (1–2 weeks' rent for a successful introduction) or the tenant (£100–£300 for finding them a suitable property). Always agree fees in writing before introductions.", "⚠ Since 2019, the Tenant Fees Act makes it ILLEGAL to charge tenants certain fees — including admin fees, referencing fees, or credit check fees. You CAN charge a holding deposit (max 1 week's rent) and a reasonable finder's fee if agreed upfront and transparently. Never misrepresent what you are charging for.", "Build your network aggressively: join every Ethiopian, Eritrean, Somali, Sudanese, and East African WhatsApp group you can find. Attend community events, mosques, churches, and cultural gatherings. Word of mouth in diaspora communities is faster and more trusted than any advertising platform.", "Find landlords: many landlords in areas with large immigrant communities specifically want a bilingual agent who can find reliable tenants. Contact letting agencies in your area and offer to refer tenants to them in exchange for a referral fee. Contact private landlords directly on SpareRoom, Gumtree, and Facebook Marketplace — tell them you can find vetted tenants from the community.", "Understand the basic documents: every rental needs an AST (Assured Shorthold Tenancy Agreement — templates free at gov.uk), the landlord must protect the deposit in a government-approved scheme (DPS, MyDeposits, TDS) within 30 days, the property must have an EPC rating of E or above, a valid gas safety certificate (annual), and an EICR electrical report.", "Build a professional credential: the PropertyMark Level 3 Award in Property (formerly NAEA Level 3) costs £250–£500 and is the standard estate agency qualification. This demonstrates competence to landlords and agencies. NAEA Propertymark membership (propertymark.co.uk) is recognised by all major estate agents.", "Income potential: a bilingual agent in London charging landlords 1 week's rent per successful letting for a £1,200/month flat earns £1,200 per placement. 5 placements a month = £6,000. In lower-rent cities (Birmingham, Leeds, Sheffield), fees are lower but volume can be higher. Specialist community knowledge commands premium fees.", "Legal protection: always use written agreements for your finder's fees, even a simple WhatsApp message confirming the fee is better than nothing. Keep records of every introduction you make. If a dispute arises, Citizens Advice and ACAS can advise.", "Long-term growth: once established, you can progress to: becoming a fully registered letting agent (register with a Property Redress Scheme), launching your own agency focusing on the diaspora community, partnering with housing associations that want bilingual liaison workers, or advising on property investment for diaspora members who want to buy to let.", "⭐ Your RICS valuation background gives you an extraordinary advantage — you understand property values, condition assessment, and market analysis better than most estate agents. This is a rare skill combination in the UK African community."] } }, cost: "Free to start — PropertyMark Level 3 £250–£500", time: "Start immediately (free phase) / Professional credential 3–6 months", bring: [], links: [{ name: "PropertyMark — Level 3 Qualification", url: "https://www.propertymark.co.uk/professional-development/qualifications-licensing/propertymark-qualifications.html" }, { name: "Property Redress Scheme (letting agent registration)", url: "https://www.theprs.co.uk" }, { name: "Deposit Protection Service (DPS)", url: "https://www.depositprotection.com" }, { name: "Tenant Fees Act guidance (GOV.UK)", url: "https://www.gov.uk/government/collections/tenant-fees-act" }, { name: "Free AST templates (GOV.UK)", url: "https://www.gov.uk/tenancy-agreements-a-guide-for-landlords" }, { name: "SpareRoom — list and find rooms", url: "https://www.spareroom.co.uk" }, { name: "RICS — property valuation careers", url: "https://www.rics.org/careers-in-surveying/become-a-member" }] },
  { id: "women-support", cat: "Community", icon: "♀️", content: { en: { title: "Support for Women & Girls", summary: "Specialist services, career paths, safety, and rights for refugee women and girls in the UK.", steps: ["Women for Refugee Women: free support, legal advice, campaigning, community for women asylum seekers and refugees. Helpline: 020 7250 1239 (womenforrefugeewomen.org.uk).", "Asylum Aid: specialist legal help for women with complex asylum claims. Free, based in London, national reach.", "Refugee Women Connect (Birmingham): employment support, social activities, training specifically for refugee women.", "Survivors of sexual and gender-based violence: Freedom from Torture provides specialist free therapy — referral via GP or self-referral at freedomfromtorture.org.", "Domestic abuse: call 0808 2000 247 (free, 24/7, all languages). Safehouses are available. You WILL NOT be deported or have your case affected for leaving an abusive situation.", "Maternity care is free on the NHS from the moment you arrive — register with a GP or midwife immediately. The Maternity Action helpline advises on rights: 0808 802 0029.", "Child benefit: claim from your refugee grant date (max 3 months back). If you are a lone parent, you automatically have priority need for housing.", "Career paths with strong demand for women from refugee backgrounds: Social Work (excellent progression, good pay from day one), Healthcare (Band 2 HCA: start within weeks), Childcare and Early Years Education, Teaching Assistants, Translation & Interpreting (rare language speakers are paid well).", "Free vocational training targeted at women: ESOL with childcare (many colleges offer this together), Care Certificate (care home funded), Skills Bootcamps (government-funded, open to all genders).", "Safety planning: if you feel unsafe, contact the police on 101 (non-emergency) or 999 (emergency). Police do NOT report to immigration enforcement. Your safety always comes first.", "Girls aged 16–18: dedicated support through the Prince's Trust (free education, employment and life-skills programmes) and Catch22 (mentoring and training for young women).", "⚠ Female Genital Mutilation (FGM): illegal in the UK. Anyone threatened with FGM can call the NSPCC FGM helpline: 0800 028 3550 (free, 24/7). You will be protected, not prosecuted."] } }, cost: "Free", time: "Access services immediately", bring: [], links: [{ name: "Women for Refugee Women", url: "https://www.womenforrefugeewomen.org.uk" }, { name: "Freedom from Torture", url: "https://www.freedomfromtorture.org" }, { name: "Domestic Abuse Helpline", url: "https://www.nationaldahelpline.org.uk" }, { name: "Maternity Action", url: "https://www.maternityaction.org.uk" }, { name: "Prince's Trust (young women 16–30)", url: "https://www.princes-trust.org.uk" }, { name: "FGM NSPCC Helpline", url: "https://www.nspcc.org.uk/what-is-child-abuse/types-of-abuse/female-genital-mutilation-fgm/" }] },
];

